export * from './toast.types';
export * from './toast.variants';
export * from './toast.component';
export * from './toast.container.component';
export * from './toast.service';
export * from './toast.imports';

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { NgIcon, provideIcons } from '@ng-icons/core';
import {
  phosphorCheckCircle,
  phosphorInfo,
  phosphorWarning,
  phosphorX,
  phosphorXCircle,
} from '@ng-icons/phosphor-icons/regular';

import { cn } from '{{alias}}/utils';
import { HbButtonComponent } from '{{alias}}/button';
import { HbSpinnerComponent } from '{{alias}}/spinner';
import type { HbToastAction, HbToastRef, HbToastType } from './toast.types';
import {
  TOAST_ICON,
  TOAST_ICON_COLOR,
  TOAST_PROGRESS_COLOR,
  toastVariants,
} from './toast.variants';

@Component({
  selector: 'hb-toast',
  imports: [NgIcon, HbButtonComponent, HbSpinnerComponent],
  viewProviders: [
    provideIcons({ phosphorCheckCircle, phosphorInfo, phosphorWarning, phosphorXCircle, phosphorX }),
  ],
  template: `
    <div
      [class]="cardClasses()"
      role="status"
      aria-live="polite"
      (mouseenter)="onEnter()"
      (mouseleave)="onLeave()"
    >
      @if (type() === 'loading') {
        <hb-spinner hbSize="sm" class="mt-0.5 shrink-0" />
      } @else if (iconName()) {
        <ng-icon [name]="iconName()" [class]="cn('mt-0.5 shrink-0 text-lg', iconColor())" />
      }

      <div class="flex min-w-0 flex-1 flex-col gap-1">
        @if (config().title) {
          <div class="text-sm font-semibold leading-none">{{ config().title }}</div>
        }
        @if (config().description) {
          <div class="text-sm text-muted-foreground">{{ config().description }}</div>
        }
        @if (actions().length) {
          <div class="mt-2 flex flex-wrap gap-2">
            @for (action of actions(); track action.label) {
              <button
                hb-button
                [hbType]="action.type ?? 'outline'"
                hbSize="sm"
                type="button"
                (click)="runAction(action)"
              >
                {{ action.label }}
              </button>
            }
          </div>
        }
      </div>

      @if (config().closable) {
        <button
          type="button"
          class="-mr-1 -mt-1 inline-flex size-6 shrink-0 items-center justify-center rounded-md text-muted-foreground transition-colors hover:bg-muted hover:text-foreground"
          aria-label="Close"
          (click)="ref().dismiss()"
        >
          <ng-icon name="phosphorX" />
        </button>
      }

      @if (showProgress()) {
        <span
          [class]="cn('absolute inset-x-0 bottom-0 h-0.5 origin-left', progressColor())"
          [style.animation]="'hb-toast-progress ' + config().duration + 'ms linear forwards'"
          [style.animationPlayState]="ref().paused() ? 'paused' : 'running'"
        ></span>
      }
    </div>
  `,
  styles: `
    @keyframes hb-toast-progress {
      from {
        transform: scaleX(1);
      }
      to {
        transform: scaleX(0);
      }
    }
    @keyframes hb-toast-in {
      from {
        opacity: 0;
        transform: translateY(0.5rem) scale(0.98);
      }
      to {
        opacity: 1;
        transform: translateY(0) scale(1);
      }
    }
    hb-toast {
      display: block;
      animation: hb-toast-in 0.18s ease-out;
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: { '[attr.data-slot]': "'toast'" },
  exportAs: 'hbToast',
})
export class HbToastComponent {
  readonly ref = input.required<HbToastRef>();
  protected readonly cn = cn;

  protected readonly config = computed(() => this.ref().config());
  protected readonly type = computed<HbToastType>(() => this.config().type ?? 'default');
  protected readonly actions = computed<HbToastAction[]>(() => this.config().actions ?? []);

  protected readonly iconName = computed(() => {
    const custom = this.config().icon;
    return custom !== undefined ? custom : TOAST_ICON[this.type()];
  });
  protected readonly iconColor = computed(() => TOAST_ICON_COLOR[this.type()]);
  protected readonly progressColor = computed(() => TOAST_PROGRESS_COLOR[this.type()]);
  protected readonly showProgress = computed(
    () =>
      !!this.config().progressBar &&
      this.type() !== 'loading' &&
      (this.config().duration ?? 0) > 0,
  );
  protected readonly cardClasses = computed(() =>
    cn(toastVariants({ type: this.type() }), this.config().class),
  );

  protected onEnter(): void {
    if (this.config().pauseOnHover) this.ref().pause();
  }
  protected onLeave(): void {
    if (this.config().pauseOnHover) this.ref().resume();
  }
  protected runAction(action: HbToastAction): void {
    action.onClick?.(this.ref());
    if (action.closeOnClick !== false) this.ref().dismiss();
  }
}

import { ChangeDetectionStrategy, Component, input, ViewEncapsulation } from '@angular/core';

import { HbToastComponent } from './toast.component';
import type { HbToastRef } from './toast.types';

@Component({
  selector: 'hb-toast-container',
  imports: [HbToastComponent],
  template: `
    @for (ref of toasts(); track ref.id) {
      <hb-toast [ref]="ref" />
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'hostClass()',
    '[style.gap]': 'gap()',
    '[attr.data-slot]': "'toast-container'",
    'aria-live': 'polite',
  },
  exportAs: 'hbToastContainer',
})
export class HbToastContainerComponent {
  readonly toasts = input<HbToastRef[]>([]);
  readonly gap = input<string>('0.75rem');
  readonly hostClass = input<string>('pointer-events-none flex flex-col');
}

import { HbToastComponent } from './toast.component';
import { HbToastContainerComponent } from './toast.container.component';

export const HbToastImports = [HbToastComponent, HbToastContainerComponent] as const;

import {
  type ComponentRef,
  Injectable,
  Injector,
  type Provider,
  inject,
  signal,
} from '@angular/core';
import { Overlay, type OverlayRef } from '@angular/cdk/overlay';
import { ComponentPortal } from '@angular/cdk/portal';

import { HbToastContainerComponent } from './toast.container.component';
import {
  HB_TOAST_CONFIG,
  HB_TOAST_DEFAULTS,
  type HbToastConfig,
  type HbToastGlobalConfig,
  type HbToastPosition,
  type HbToastRef,
} from './toast.types';

type Message = string;
type Resolvable<T> = string | ((value: T) => string);
const resolve = <T>(m: Resolvable<T>, value: T): string =>
  typeof m === 'function' ? m(value) : m;

class HbToastInstance implements HbToastRef {
  private readonly cfg = signal<HbToastConfig>({});
  private readonly pausedSig = signal(false);
  private readonly visibleSig = signal(false);
  readonly config = this.cfg.asReadonly();
  readonly paused = this.pausedSig.asReadonly();
  readonly visible = this.visibleSig.asReadonly();
  readonly position: HbToastPosition;

  private timeoutId: ReturnType<typeof setTimeout> | null = null;
  private startedAt = 0;
  private remaining: number;

  constructor(
    readonly id: number,
    initial: HbToastConfig,
    private readonly onRemove: (id: number) => void,
  ) {
    this.cfg.set(initial);
    this.position = initial.position ?? 'bottom-right';
    this.remaining = initial.duration ?? 0;
  }

  makeVisible(): void {
    if (this.visibleSig()) return;
    this.visibleSig.set(true);
    this.remaining = this.cfg().duration ?? 0;
    this.startTimer();
  }

  private startTimer(): void {
    this.clearTimer();
    const c = this.cfg();
    if (c.type === 'loading' || !(c.duration && c.duration > 0)) return;
    this.startedAt = Date.now();
    this.timeoutId = setTimeout(() => this.dismiss(), this.remaining);
  }
  private clearTimer(): void {
    if (this.timeoutId) {
      clearTimeout(this.timeoutId);
      this.timeoutId = null;
    }
  }

  pause(): void {
    if (!this.visibleSig() || this.pausedSig() || !this.timeoutId) return;
    this.remaining -= Date.now() - this.startedAt;
    this.clearTimer();
    this.pausedSig.set(true);
  }
  resume(): void {
    if (!this.pausedSig()) return;
    this.pausedSig.set(false);
    this.startTimer();
  }
  update(patch: Partial<HbToastConfig>): void {
    const next = { ...this.cfg(), ...patch };
    this.cfg.set(next);
    this.remaining = next.duration ?? 0;
    this.pausedSig.set(false);
    if (this.visibleSig()) this.startTimer();
  }
  dismiss(): void {
    this.clearTimer();
    this.cfg().onDismiss?.();
    this.onRemove(this.id);
  }
  destroy(): void {
    this.clearTimer();
  }
}

@Injectable({ providedIn: 'root' })
export class HbToastService {
  private readonly overlay = inject(Overlay);
  private readonly injector = inject(Injector);
  private readonly resolved: HbToastGlobalConfig = {
    ...HB_TOAST_DEFAULTS,
    ...(inject(HB_TOAST_CONFIG, { optional: true }) ?? {}),
  };

  private readonly instances = signal<HbToastInstance[]>([]);
  private readonly overlays = new Map<
    HbToastPosition,
    { overlayRef: OverlayRef; compRef: ComponentRef<HbToastContainerComponent> }
  >();
  private counter = 0;

  show(config: HbToastConfig): HbToastRef {
    const inst = new HbToastInstance(++this.counter, this.merge(config), (id) => this.remove(id));
    this.instances.update((list) => [...list, inst]);
    this.reconcile(inst.position);
    this.ensureOverlay(inst.position);
    this.push();
    return inst;
  }

  default(title: Message, opts?: HbToastConfig): HbToastRef {
    return this.show({ ...opts, type: 'default', title });
  }
  success(title: Message, opts?: HbToastConfig): HbToastRef {
    return this.show({ ...opts, type: 'success', title });
  }
  info(title: Message, opts?: HbToastConfig): HbToastRef {
    return this.show({ ...opts, type: 'info', title });
  }
  warning(title: Message, opts?: HbToastConfig): HbToastRef {
    return this.show({ ...opts, type: 'warning', title });
  }
  destructive(title: Message, opts?: HbToastConfig): HbToastRef {
    return this.show({ ...opts, type: 'destructive', title });
  }
  loading(title: Message, opts?: HbToastConfig): HbToastRef {
    return this.show({ ...opts, type: 'loading', title });
  }

  promise<T>(
    promise: Promise<T>,
    messages: { loading: Message; success: Resolvable<T>; error: Resolvable<unknown> },
    opts?: HbToastConfig,
  ): HbToastRef {
    const ref = this.loading(messages.loading, opts);
    promise
      .then((value) =>
        ref.update({
          type: 'success',
          title: resolve(messages.success, value),
          duration: this.resolved.duration,
        }),
      )
      .catch((err) =>
        ref.update({
          type: 'destructive',
          title: resolve(messages.error, err),
          duration: this.resolved.duration,
        }),
      );
    return ref;
  }

  dismiss(id?: number): void {
    if (id === undefined) return this.clear();
    this.instances()
      .find((i) => i.id === id)
      ?.dismiss();
  }
  clear(): void {
    [...this.instances()].forEach((i) => i.dismiss());
  }

  private remove(id: number): void {
    const inst = this.instances().find((i) => i.id === id);
    const pos = inst?.position;
    inst?.destroy();
    this.instances.update((list) => list.filter((i) => i.id !== id));
    if (pos) {
      this.reconcile(pos);
      this.push();
      this.maybeDisposeOverlay(pos);
    }
  }

  private reconcile(position: HbToastPosition): void {
    const max = this.resolved.maxVisible;
    const inPos = this.instances().filter((i) => i.position === position);
    inPos.forEach((inst, idx) => {
      if (max <= 0 || idx < max) inst.makeVisible();
    });
  }

  private push(): void {
    for (const [pos, o] of this.overlays) {
      const visible = this.instances().filter((i) => i.position === pos && i.visible());
      const ordered = pos.startsWith('top') ? [...visible].reverse() : visible;
      o.compRef.setInput('toasts', ordered);
      o.compRef.setInput('gap', this.resolved.gap);
      o.compRef.setInput('hostClass', this.hostClass(pos));
      o.compRef.changeDetectorRef.markForCheck();
    }
  }

  private ensureOverlay(position: HbToastPosition): void {
    if (this.overlays.has(position)) return;
    const overlayRef = this.overlay.create({
      positionStrategy: this.buildPosition(position),
      hasBackdrop: false,
      scrollStrategy: this.overlay.scrollStrategies.noop(),
      panelClass: 'hb-toast-overlay',
    });
    const compRef = overlayRef.attach(
      new ComponentPortal(HbToastContainerComponent, null, this.injector),
    );
    this.overlays.set(position, { overlayRef, compRef });
  }

  private maybeDisposeOverlay(position: HbToastPosition): void {
    const has = this.instances().some((i) => i.position === position);
    if (has) return;
    this.overlays.get(position)?.overlayRef.dispose();
    this.overlays.delete(position);
  }

  private buildPosition(position: HbToastPosition) {
    const s = this.overlay.position().global();
    const o = this.resolved.offset;
    switch (position) {
      case 'top-left':
        return s.top(o).left(o);
      case 'top-center':
        return s.top(o).centerHorizontally();
      case 'top-right':
        return s.top(o).right(o);
      case 'bottom-left':
        return s.bottom(o).left(o);
      case 'bottom-center':
        return s.bottom(o).centerHorizontally();
      case 'bottom-right':
        return s.bottom(o).right(o);
      case 'center':
        return s.centerHorizontally().centerVertically();
    }
  }

  private hostClass(position: HbToastPosition): string {
    const align = position.endsWith('left')
      ? 'items-start'
      : position.endsWith('right')
        ? 'items-end'
        : 'items-center';
    return `pointer-events-none flex flex-col ${align}`;
  }

  private merge(c: HbToastConfig): HbToastConfig {
    const d = this.resolved;
    const type = c.type ?? 'default';
    return {
      type,
      title: c.title,
      description: c.description,
      icon: c.icon,
      actions: c.actions,
      class: c.class,
      onDismiss: c.onDismiss,
      position: c.position ?? d.position,
      closable: c.closable ?? d.closable,
      pauseOnHover: c.pauseOnHover ?? d.pauseOnHover,
      progressBar: c.progressBar ?? d.progressBar,
      duration: type === 'loading' ? 0 : (c.duration ?? d.duration),
    };
  }
}

export function provideHbToast(config: Partial<HbToastGlobalConfig>): Provider {
  return { provide: HB_TOAST_CONFIG, useValue: config };
}

import { InjectionToken, type Signal } from '@angular/core';

import type { ClassValue } from '{{alias}}/utils';

export type HbToastType =
  | 'default'
  | 'success'
  | 'warning'
  | 'destructive'
  | 'info'
  | 'loading';

export type HbToastPosition =
  | 'top-left'
  | 'top-center'
  | 'top-right'
  | 'bottom-left'
  | 'bottom-center'
  | 'bottom-right'
  | 'center';

export interface HbToastAction {
  label: string;
  onClick?: (ref: HbToastRef) => void;
  type?: 'default' | 'secondary' | 'outline' | 'ghost' | 'destructive' | 'link';
  closeOnClick?: boolean;
}

export interface HbToastConfig {
  type?: HbToastType;
  title?: string;
  description?: string;
  icon?: string;
  duration?: number;
  position?: HbToastPosition;
  closable?: boolean;
  pauseOnHover?: boolean;
  progressBar?: boolean;
  actions?: HbToastAction[];
  class?: ClassValue;
  onDismiss?: () => void;
}

export interface HbToastGlobalConfig {
  position: HbToastPosition;
  duration: number;
  closable: boolean;
  pauseOnHover: boolean;
  progressBar: boolean;
  maxVisible: number;
  gap: string;
  offset: string;
}

export const HB_TOAST_DEFAULTS: HbToastGlobalConfig = {
  position: 'bottom-right',
  duration: 4000,
  closable: true,
  pauseOnHover: true,
  progressBar: false,
  maxVisible: 0,
  gap: '0.75rem',
  offset: '1rem',
};

export const HB_TOAST_CONFIG = new InjectionToken<Partial<HbToastGlobalConfig>>('HB_TOAST_CONFIG');

export interface HbToastRef {
  readonly id: number;
  readonly config: Signal<HbToastConfig>;
  readonly paused: Signal<boolean>;
  readonly visible: Signal<boolean>;
  dismiss(): void;
  pause(): void;
  resume(): void;
  update(patch: Partial<HbToastConfig>): void;
}

import { cva } from 'class-variance-authority';

import type { HbToastType } from './toast.types';

export const toastVariants = cva(
  'pointer-events-auto relative flex w-[356px] max-w-[calc(100vw-2rem)] items-start gap-3 overflow-hidden rounded-lg border bg-popover p-4 text-popover-foreground shadow-lg',
  {
    variants: {
      type: {
        default: 'border-border',
        info: 'border-border',
        success: 'border-success/40',
        warning: 'border-warning/40',
        destructive: 'border-destructive/40',
        loading: 'border-border',
      },
    },
    defaultVariants: { type: 'default' },
  },
);

export const TOAST_ICON_COLOR: Record<HbToastType, string> = {
  default: 'text-foreground',
  info: 'text-foreground',
  success: 'text-success',
  warning: 'text-warning',
  destructive: 'text-destructive',
  loading: 'text-muted-foreground',
};

export const TOAST_ICON: Record<HbToastType, string> = {
  default: '',
  info: 'phosphorInfo',
  success: 'phosphorCheckCircle',
  warning: 'phosphorWarning',
  destructive: 'phosphorXCircle',
  loading: '',
};

export const TOAST_PROGRESS_COLOR: Record<HbToastType, string> = {
  default: 'bg-primary',
  info: 'bg-primary',
  success: 'bg-success',
  warning: 'bg-warning',
  destructive: 'bg-destructive',
  loading: 'bg-primary',
};

